import * as React from 'react';
import { Form } from './packages/react/src/form';
import { Field } from './packages/react/src/field';
import { createRenderer, fireEvent, screen } from '@mui/internal-test-utils';

// Test case to reproduce the bug with dynamic Field.Root components
describe('Dynamic Field.Root components', () => {
  const { render } = createRenderer();

  it('should not throw error when dynamically adding/removing Field.Root components and submitting', async () => {
    function DynamicForm() {
      const [showField, setShowField] = React.useState(true);

      return (
        <Form onSubmit={(event) => event.preventDefault()}>
          <Field.Root name="static">
            <Field.Control required defaultValue="" data-testid="static-input" />
          </Field.Root>

          {showField && (
            <Field.Root name="dynamic">
              <Field.Control required defaultValue="" data-testid="dynamic-input" />
            </Field.Root>
          )}

          <button
            type="button"
            onClick={() => setShowField(!showField)}
            data-testid="toggle-button"
          >
            Toggle Field
          </button>

          <button type="submit" data-testid="submit-button">
            Submit
          </button>
        </Form>
      );
    }

    render(<DynamicForm />);

    const toggleButton = screen.getByTestId('toggle-button');
    const submitButton = screen.getByTestId('submit-button');

    // Quickly toggle the field on/off (simulating fast clicking)
    fireEvent.click(toggleButton); // Remove dynamic field
    fireEvent.click(toggleButton); // Add dynamic field back

    // Try to submit form - this should not throw an error
    expect(() => {
      fireEvent.submit(submitButton);
    }).not.to.throw();

    // Remove the dynamic field and submit
    fireEvent.click(toggleButton); // Remove dynamic field again
    expect(() => {
      fireEvent.submit(submitButton);
    }).not.to.throw();
  });

  it('should handle focus correctly even when invalid controls are removed', () => {
    function DynamicFocusForm() {
      const [fields, setFields] = React.useState(["field1", "field2"]);

      return (
        <Form onSubmit={(event) => event.preventDefault()}>
          {fields.map((fieldName) => (
            <Field.Root key={fieldName} name={fieldName}>
              <Field.Control required defaultValue="" />
            </Field.Root>
          ))}

          <button
            type="button"
            onClick={() => setFields(["field1"])}
            data-testid="remove-button"
          >
            Remove Field 2
          </button>

          <button type="submit" data-testid="submit-button">
            Submit
          </button>
        </Form>
      );
    }

    render(<DynamicFocusForm />);

    const removeButton = screen.getByTestId('remove-button');
    const submitButton = screen.getByTestId('submit-button');

    // Submit with both fields present (will be invalid due to empty required fields)
    fireEvent.submit(submitButton);

    // Remove a field
    fireEvent.click(removeButton);

    // Submit again - should not throw error about focusing undefined control
    expect(() => {
      fireEvent.submit(submitButton);
    }).not.to.throw();
  });
});

