// Simple test to validate the fix logic
// This simulates the scenario where controlRef.current can be null

// Simulate the form's fields map with some fields having null controlRef
const fields = new Map();

// Add a field with a valid controlRef
fields.set('field1', {
  controlRef: { current: { focus: () => console.log('Focusing field1') } },
  validityData: { state: { valid: false } }
});

// Add a field with null controlRef (simulating unmounted field)
fields.set('field2', {
  controlRef: { current: null },
  validityData: { state: { valid: false } }
});

// Add another invalid field with null controlRef
fields.set('field3', {
  controlRef: { current: null },
  validityData: { state: { valid: false } }
});

// Original buggy code snippet (would throw error)
console.log('Testing original buggy logic:');
try {
  const invalidFields = Array.from(fields.values()).filter(
    (field) => field.validityData.state.valid === false,
  );

  if (invalidFields.length) {
    // This would throw: Cannot read properties of null (reading 'focus')
    invalidFields[0].controlRef.current.focus();
  }
} catch (error) {
  console.log('❌ Original logic failed:', error.message);
}

// Fixed code snippet
console.log('\nTesting fixed logic:');
try {
  const invalidFields = Array.from(fields.values()).filter(
    (field) => field.validityData.state.valid === false,
  );

  if (invalidFields.length) {
    // Find the first invalid field with a valid control reference
    const firstInvalidField = invalidFields.find(field => field.controlRef.current);
    if (firstInvalidField) {
      firstInvalidField.controlRef.current.focus();
      console.log('✅ Fixed logic worked correctly');
    } else {
      console.log('✅ No fields with valid controls to focus on');
    }
  }
} catch (error) {
  console.log('❌ Fixed logic failed:', error.message);
}

// Test the focusControl function with null input
console.log('\nTesting focusControl with null input:');
const focusControl = (control) => {
  if (control) {
    control.focus();
    if (control.tagName === 'INPUT') {
      control.select();
    }
  }
};

try {
  focusControl(null); // Should not throw
  console.log('✅ focusControl handles null correctly');
} catch (error) {
  console.log('❌ focusControl failed with null:', error.message);
}

